import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse(`{"title":"Simon Willison's Weblog — 2026-05-24","description":"","frontmatter":{"title":"Simon Willison's Weblog — 2026-05-24","date":"2026-05-24T00:00:00.000Z","source":"Simon Willison's Weblog","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-24-simon-willisons-weblog.md","filePath":"research/ai-news/2026-05/2026-05-24-simon-willisons-weblog.md","lastUpdated":1779899342000}`),o={name:"research/ai-news/2026-05/2026-05-24-simon-willisons-weblog.md"};function i(s,e,l,h,d,g){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔧-simon-willison-s-weblog-—-2026-05-24" tabindex="-1">🔧 Simon Willison&#39;s Weblog — 2026-05-24 <a class="header-anchor" href="#🔧-simon-willison-s-weblog-—-2026-05-24" aria-label="Permalink to &quot;🔧 Simon Willison&#39;s Weblog — 2026-05-24&quot;">​</a></h1><blockquote><p>datasette / llm-cli 作者；AI 工具工程實踐與安全分析密度最高的個人部落格 來源：<a href="https://simonwillison.net/atom/everything/" target="_blank" rel="noreferrer">Simon Willison&#39;s Weblog</a></p></blockquote><hr><h2 id="on-the" tabindex="-1"><a href="https://simonwillison.net/2026/May/23/on-the-dl/#atom-everything" target="_blank" rel="noreferrer">On the</a> <a class="header-anchor" href="#on-the" aria-label="Permalink to &quot;[On the](https://simonwillison.net/2026/May/23/on-the-dl/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-23</em></p><p><strong><a href="https://benmyers.dev/blog/on-the-dl/" target="_blank" rel="noreferrer">On <code>the&lt;dl&gt;</code></a></strong></p><p>I learned a few new-to-me things about the <code>&lt;dl&gt;</code> element from this article by Ben Meyer:</p><ol><li>A <code>&lt;dt&gt;</code> can be followed by <em>multiple</em> <code>&lt;dd&gt;</code></li><li>You can optionally group the <code>&lt;dt&gt;</code> and <code>&lt;dd&gt;</code> elements in a <code>&lt;div&gt;</code> for styling - but only a <code>&lt;div&gt;</code>.</li><li>You can label them using ARIA.</li><li>They&#39;ve been called &quot;description lists&quot;, not &quot;definition lists&quot;, since <a href="https://www.w3.org/TR/2008/WD-html5-20080122/#the-dl" target="_blank" rel="noreferrer">an HTML5 draft in 2008</a>.</li></ol><p>So this is valid:</p><pre><code>`&lt;h2 id=&quot;credits&quot;&gt;`Credits`&lt;/h2&gt;`\n`&lt;dl aria-labelledby=&quot;credits&quot;&gt;`\n  `&lt;div&gt;`\n    `&lt;dt&gt;`Author`&lt;/dt&gt;`\n    `&lt;dd&gt;`Jeffrey Zeldman`&lt;/dd&gt;`\n    `&lt;dd&gt;`Ethan Marcotte`&lt;/dd&gt;`\n  `&lt;/div&gt;`\n`&lt;/dl&gt;`\n</code></pre><p>Here&#39;s a useful note from Adrian Roselli on <a href="https://adrianroselli.com/2025/01/updated-brief-note-on-description-list-support.html" target="_blank" rel="noreferrer">screen reader support for description lists</a>.</p><p>Via <a href="https://news.ycombinator.com/item?id=48247325" target="_blank" rel="noreferrer">Hacker News</a></p><p>Tags: <a href="https://simonwillison.net/tags/css" target="_blank" rel="noreferrer">css</a>, <a href="https://simonwillison.net/tags/html" target="_blank" rel="noreferrer">html</a>, <a href="https://simonwillison.net/tags/screen-readers" target="_blank" rel="noreferrer">screen-readers</a>, <a href="https://simonwillison.net/tags/web-standards" target="_blank" rel="noreferrer">web-standards</a></p><hr><h2 id="the-memory-shortage-is-causing-a-repricing-of-consumer-electronics" tabindex="-1"><a href="https://simonwillison.net/2026/May/22/memory-shortage/#atom-everything" target="_blank" rel="noreferrer">The memory shortage is causing a repricing of consumer electronics</a> <a class="header-anchor" href="#the-memory-shortage-is-causing-a-repricing-of-consumer-electronics" aria-label="Permalink to &quot;[The memory shortage is causing a repricing of consumer electronics](https://simonwillison.net/2026/May/22/memory-shortage/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-22</em></p><p><strong><a href="https://davidoks.blog/p/ai-is-killing-the-cheap-smartphone" target="_blank" rel="noreferrer">The memory shortage is causing a repricing of consumer electronics</a></strong></p><p>David Oks provides the clearest explanation I&#39;ve seen yet of why consumer products that use memory are likely to get significantly more expensive over the next few years.</p><p>The short version is that memory manufacturers - of which there are just three remaining large companies - have a fixed capacity in terms of how many wafers they can process at any one time. This fixed wafer capacity is then split between DDR - used in desktops and servers, LPDDR - used in mobile phones and low-energy devices, and HBM - used with GPUs.</p><p>Until recently, HBM got just 2% of that wafer allocation. The enormous growth in AI data centers has pushed that up to an expected 20% by the end of 2026, and &quot;a single gigabyte of HBM consumes more than three times the wafer capacity that a gigabyte of DDR or LPDDR does&quot;.</p><p>Memory companies have learned from the extinction of their rivals that you should always under-provision rather than over-provision your fabricator capacity. The profit margins and demand for HBM (high-bandwidth memory) will constrain the production of consumer-device RAM for several years.</p><p>This is already being felt in the sub-$100 smartphone market, which is particularly important to markets like Africa and South Asia.</p><p>(The original title of the piece was &quot;AI is killing the cheap smartphone&quot; but I&#39;m using the Hacker News rephrased title, which I think does more justice to the content.)</p><p>Via <a href="https://news.ycombinator.com/item?id=48229319" target="_blank" rel="noreferrer">Hacker News</a></p><p>Tags: <a href="https://simonwillison.net/tags/memory" target="_blank" rel="noreferrer">memory</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/ai-ethics" target="_blank" rel="noreferrer">ai-ethics</a></p><hr><h2 id="ftc-to-require-cox-media-group-two-other-firms-to-pay-nearly-1-million-to-settle-charges-they-deceived-customers-about" tabindex="-1"><a href="https://simonwillison.net/2026/May/22/ftc-active-listening/#atom-everything" target="_blank" rel="noreferrer">FTC to Require Cox Media Group, Two Other Firms to Pay Nearly $1 Million to Settle Charges They Deceived Customers About…</a> <a class="header-anchor" href="#ftc-to-require-cox-media-group-two-other-firms-to-pay-nearly-1-million-to-settle-charges-they-deceived-customers-about" aria-label="Permalink to &quot;[FTC to Require Cox Media Group, Two Other Firms to Pay Nearly $1 Million to Settle Charges They Deceived Customers About…](https://simonwillison.net/2026/May/22/ftc-active-listening/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-22</em></p><p><strong><a href="https://www.ftc.gov/news-events/news/press-releases/2026/05/ftc-require-cox-media-group-two-other-firms-pay-nearly-1-million-settle-charges-they-deceived" target="_blank" rel="noreferrer">FTC to Require Cox Media Group, Two Other Firms to Pay Nearly $1 Million to Settle Charges They Deceived Customers About “Active Listening” AI-Powered Marketing Service</a></strong></p><p>Back in 2024 Cox Media Group were caught trying to sell advertisers packages based on &quot;active listening&quot;, with <a href="https://www.documentcloud.org/documents/25051283-cmg-pitch-deck-on-voice-data-advertising-active-listening/" target="_blank" rel="noreferrer">this deck</a> which claimed:</p><blockquote><ul><li>Smart devices capture real-time intent data by listening to our conversations</li><li>Advertisers can pair this voice-data with behavioral data to target in-market consumers</li></ul></blockquote><p>I wrote about this <a href="https://simonwillison.net/2024/Sep/2/facebook-cmg/" target="_blank" rel="noreferrer">in September 2024</a>. My theory:</p><blockquote><p>I think <strong>active listening</strong> is the term that the team came up with for “something that sounds fancy but really just means the way ad targeting platforms work already”. Then they got over-excited about the new metaphor and added that first couple of slides that talk about “voice data”, without really understanding how the tech works or what kind of a shitstorm that could kick off when people who DID understand technology started paying attention to their marketing.</p></blockquote><p>This FTC press release appears to confirm that&#39;s pretty much what happened:</p><blockquote><p>CMG, MindSift and 1010 Digital Works claimed their “Active Listening” branded marketing service listened in on consumers’ conversations overheard by smart devices, in real time, to target advertising [...]</p><p>According to the complaints, this service did not, in fact, listen in on consumers’ conversations or use voice data at all—nor did the service accurately place ads in customers’ desired locations. Instead, the service the companies provided consisted of reselling—at a significant markup—email lists obtained from other data brokers.</p></blockquote><p>The FTC also clarify that hiding an &quot;opt-in&quot; to using voice data in terms of service would not be acceptable, as tricks like that do not constitute &quot;adequate consent&quot;:</p><blockquote><p>The FTC also alleged that all three companies deceived potential customers by claiming that consumers had opted into the Active Listening service. The company, however, did not seek or obtain consumers’ consent, according to the complaints. Instead, the companies claimed that consumers had “opted in” by agreeing to the terms of service that people have to accept when downloading and using apps. Clicking through mandatory terms of service does not constitute “opt-in consent” for such an invasive service or for use of consumers’ voice data from inside their homes. If the Active Listening service had functioned as advertised, this collection and use of consumers’ voice data without adequate consent would itself violate Section 5 of the FTC Act.</p></blockquote><p>Attempting to myth bust <a href="https://simonwillison.net/tags/microphone-ads-conspiracy/" target="_blank" rel="noreferrer">the conspiracy theory</a> that our mobile devices target ads to us based on spying through the microphones continues to be my least rewarding niche online hobby. It&#39;s nice to have a new piece of ammunition.</p><p>Via <a href="https://twitter.com/nydiatisdale/status/2057657844321705993" target="_blank" rel="noreferrer">@nydiatisdale</a></p><p>Tags: <a href="https://simonwillison.net/tags/privacy" target="_blank" rel="noreferrer">privacy</a>, <a href="https://simonwillison.net/tags/microphone-ads-conspiracy" target="_blank" rel="noreferrer">microphone-ads-conspiracy</a></p><hr><h2 id="datasette-agent" tabindex="-1"><a href="https://simonwillison.net/2026/May/21/datasette-agent/#atom-everything" target="_blank" rel="noreferrer">Datasette Agent</a> <a class="header-anchor" href="#datasette-agent" aria-label="Permalink to &quot;[Datasette Agent](https://simonwillison.net/2026/May/21/datasette-agent/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-21</em></p><p>We just <a href="https://datasette.io/blog/2026/datasette-agent/" target="_blank" rel="noreferrer">announced the first release of Datasette Agent</a>, a new extensible AI assistant for Datasette. I&#39;ve been working on my <a href="https://llm.datasette.io/" target="_blank" rel="noreferrer">LLM</a> Python library for just over three years now, and Datasette Agent represents the moment that LLM and <a href="https://datasette.io/" target="_blank" rel="noreferrer">Datasette</a> finally come together. I&#39;m really excited about it!</p><p>Datasette Agent provides a conversational interface for asking questions of the data you have stored in Datasette. Add the <a href="https://github.com/datasette/datasette-agent-charts" target="_blank" rel="noreferrer">datasette-agent-charts</a> plugin and it can generate charts of your data as well.</p><h4 id="the-demo" tabindex="-1">The demo <a class="header-anchor" href="#the-demo" aria-label="Permalink to &quot;The demo&quot;">​</a></h4><p>The <a href="https://simonwillison.net/atom/everything/" target="_blank" rel="noreferrer">announcement post</a> (on the new Datasette project blog) includes this <a href="https://www.youtube.com/watch?v=AFZKp6hbFjI" target="_blank" rel="noreferrer">demo video</a>:</p><p>I recorded the video against the new <a href="https://agent.datasette.io/" target="_blank" rel="noreferrer">agent.datasette.io</a> live demo instance, which runs Datasette Agent against example databases including the classic <a href="https://datasette.io/global-power-plants" target="_blank" rel="noreferrer">global-power-plants</a> by <a href="https://www.wri.org/research/global-database-power-plants" target="_blank" rel="noreferrer">WRI</a>, and a copy of the <a href="https://datasette.simonwillison.net/" target="_blank" rel="noreferrer">Datasette backup</a> of my blog.</p><p>The live demo runs on <a href="https://ai.google.dev/gemini-api/docs/models/gemini-3.1-flash-lite" target="_blank" rel="noreferrer">Gemini 3.1 Flash-Lite</a> - it&#39;s cheap, fast and has no trouble writing SQLite queries.</p><p>A question I asked in the demo was:</p><blockquote><p>when did Simon most recently see a pelican?</p></blockquote><p>Which ran <a href="https://datasette.simonwillison.net/simonwillisonblog?sql=SELECT+title%2C+commentary%2C+created+FROM+blog_beat+WHERE+beat_type+%3D+%27sighting%27+AND+%28title+LIKE+%27%25pelican%25%27+OR+commentary+LIKE+%27%25pelican%25%27%29+ORDER+BY+created+DESC+LIMIT+5" target="_blank" rel="noreferrer">this SQL query</a>:</p><pre><code>SELECT\n  title, commentary, created\nFROM\n  blog_beat\nWHERE\n  beat_type = &#39;sighting&#39;\n  AND (title LIKE &#39;%pelican%&#39; OR commentary LIKE &#39;%pelican%&#39;)\nORDER BY\n  created DESC\nLIMIT\n  5\n</code></pre><p>And replied:</p><blockquote><p>The most recent sighting of a pelican by Simon was recorded on <strong>May 20, 2026</strong>.</p><p>The observation included a California Brown Pelican, along with a Common Loon, Canada Goose, Striped Shore Crab, and a California Sea Lion.</p></blockquote><p>Here&#39;s <a href="https://simonwillison.net/2026/May/20/sighting-363395265/" target="_blank" rel="noreferrer">that sighting on my blog</a>, and the <a href="https://gist.github.com/simonw/a46d17b69659a4866adb1d868280091d" target="_blank" rel="noreferrer">Markdown export</a> of the full conversation transcript.</p><h4 id="the-plugins" tabindex="-1">The plugins <a class="header-anchor" href="#the-plugins" aria-label="Permalink to &quot;The plugins&quot;">​</a></h4><p>My favorite feature of Datasette Agent is that, like the rest of Datasette, it&#39;s extensible using plugins.</p><p>We&#39;ve shipped three plugins so far:</p><ul><li><a href="https://github.com/datasette/datasette-agent-charts" target="_blank" rel="noreferrer">datasette-agent-charts</a>, shown in the video, adds charts to Datasette Agent, powered by <a href="https://observablehq.com/plot/" target="_blank" rel="noreferrer">Observable Plot</a>.</li><li><a href="https://github.com/datasette/datasette-agent-openai-imagegen" target="_blank" rel="noreferrer">datasette-agent-openai-imagegen</a> adds an image generation tool to Datasette Agent using <a href="https://openai.com/index/introducing-chatgpt-images-2-0/" target="_blank" rel="noreferrer">ChatGPT Images 2.0</a>.</li><li><a href="https://github.com/datasette/datasette-agent-sprites" target="_blank" rel="noreferrer">datasette-agent-sprites</a> provides tools for executing code in a <a href="https://sprites.dev/" target="_blank" rel="noreferrer">Fly Sprites</a> persistent sandbox.</li></ul><p>Building plugins is <em>really fun</em>. I have a bunch more prototypes that aren&#39;t quite alpha-quality yet.</p><p>Claude Code and OpenAI Codex are both proving excellent at writing plugins - just point them at a checkout of the <a href="https://github.com/datasette/datasette-agent" target="_blank" rel="noreferrer">datasette-agent repo</a> for reference and tell them what you want to build!</p><h4 id="running-it-against-local-models" tabindex="-1">Running it against local models <a class="header-anchor" href="#running-it-against-local-models" aria-label="Permalink to &quot;Running it against local models&quot;">​</a></h4><p>I&#39;ve also been having fun running the new plugin against local models. Here&#39;s a <code>uv</code> one-liner to run the plugin against <a href="https://huggingface.co/google/gemma-4-26B-A4B" target="_blank" rel="noreferrer">gemma-4-26b-a4b</a> in <a href="https://lmstudio.ai" target="_blank" rel="noreferrer">LM Studio</a> on a Mac:</p><pre><code>uvx --prerelease=allow \\\n  --with datasette-agent --with llm-lmstudio \\\n  datasette --internal internal.db --root \\\n  -s plugins.datasette-llm.default_model lmstudio/google/gemma-4-26b-a4b \\\n  data.db\n</code></pre><p>Datasette Agent needs reliable tool calls and the ability for a model to produce SQL queries that run against SQLite. The open weight models released in the past six months are increasingly able to handle that.</p><h4 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h4><p>Datasette Agent opens up <em>so many</em> opportunities for the LLM and Datasette ecosystem in general.</p><p>It&#39;s already informed <a href="https://simonwillison.net/2026/Apr/29/llm/" target="_blank" rel="noreferrer">the major LLM 0.32a0 refactor</a> which I&#39;m nearly ready to roll into a stable release, maybe with some additional &quot;LLM agent&quot; abstractions extracte from Datasette Agent itself.</p><p>I&#39;ve been exploring my own take on the Claude Artifacts, which is shaping up nicely as a plugin.</p><p>I&#39;m excited to use Datasette Agent to build my own <a href="https://simonwillison.net/2026/May/19/5-minute-llms/#5-minutes-llms.013.jpeg" target="_blank" rel="noreferrer">Claw</a> - a personal AI assistant built around data imported from different parts of my digital life, which is a neat excuse to revisit my older <a href="https://dogsheep.github.io" target="_blank" rel="noreferrer">Dogsheep</a> family of tools.</p><p>We&#39;ll also be rolling out Datasette Agent for users of <a href="https://datasette.cloud/" target="_blank" rel="noreferrer">Datasette Cloud</a>.</p><p>Join our <a href="https://discord.gg/hdxyusUFv" target="_blank" rel="noreferrer">#datasette-agent Discord channel</a> if you&#39;d like to talk about the project.</p><p>Tags: <a href="https://simonwillison.net/tags/projects" target="_blank" rel="noreferrer">projects</a>, <a href="https://simonwillison.net/tags/sqlite" target="_blank" rel="noreferrer">sqlite</a>, <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/datasette" target="_blank" rel="noreferrer">datasette</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/llm" target="_blank" rel="noreferrer">llm</a>, <a href="https://simonwillison.net/tags/uv" target="_blank" rel="noreferrer">uv</a>, <a href="https://simonwillison.net/tags/datasette-agent" target="_blank" rel="noreferrer">datasette-agent</a></p><hr><h2 id="datasette-agent-sprites-0-1a0" tabindex="-1"><a href="https://simonwillison.net/2026/May/21/datasette-agent-sprites/#atom-everything" target="_blank" rel="noreferrer">datasette-agent-sprites 0.1a0</a> <a class="header-anchor" href="#datasette-agent-sprites-0-1a0" aria-label="Permalink to &quot;[datasette-agent-sprites 0.1a0](https://simonwillison.net/2026/May/21/datasette-agent-sprites/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-21</em></p><p><strong>Release:</strong> <a href="https://github.com/datasette/datasette-agent-sprites/releases/tag/0.1a0" target="_blank" rel="noreferrer">datasette-agent-sprites 0.1a0</a></p><p>A Datasette Agent plugin for running commands in a <a href="https://sprites.dev" target="_blank" rel="noreferrer">Fly Sprites</a> sandbox.</p><p>Tags: <a href="https://simonwillison.net/tags/sandboxing" target="_blank" rel="noreferrer">sandboxing</a>, <a href="https://simonwillison.net/tags/datasette" target="_blank" rel="noreferrer">datasette</a>, <a href="https://simonwillison.net/tags/fly" target="_blank" rel="noreferrer">fly</a>, <a href="https://simonwillison.net/tags/datasette-agent" target="_blank" rel="noreferrer">datasette-agent</a></p><hr>',81)])])}const m=t(o,[["render",i]]);export{c as __pageData,m as default};
